  2→/**
  3→ * CLI for Test Tautology Detector
  4→ *
  5→ * Reads test files from git diff and outputs tautology detection results.
  6→ *
  7→ * Usage:
  8→ *   npx tsx scripts/qa/tautology-detector-cli.ts [options]
  9→ *
 10→ * Options:
 11→ *   --json     Output results as JSON
 12→ *   --verbose  Include file details in output
 13→ *
 14→ * Exit codes:
 15→ *   0 - Success (no blocking issues)
 16→ *   1 - Blocking: >50% tautological tests
 17→ *   2 - Error running detector
 18→ */
 19→
 20→import * as fs from "fs";
 21→import { execSync } from "child_process";
 22→import {
 23→  detectTautologicalTests,
 24→  formatTautologyResults,
 25→  getTautologyVerdictImpact,
 26→} from "../../src/lib/test-tautology-detector.js";
 27→
 28→interface CliArgs {
 29→  json: boolean;
 30→  verbose: boolean;
 31→}
 32→
 33→function parseArgs(): CliArgs {
 34→  const args = process.argv.slice(2);
 35→  return {
 36→    json: args.includes("--json"),
 37→    verbose: args.includes("--verbose"),
 38→  };
 39→}
 40→
 41→function getChangedTestFiles(): string[] {
 42→  try {
 43→    const output = execSync("git diff main...HEAD --name-only", {
 44→      encoding: "utf-8",
 45→    });
 46→    return output
 47→      .trim()
 48→      .split("\n")
 49→      .filter((f) => f && /\.(test|spec)\.[jt]sx?$/.test(f));
 50→  } catch {
 51→    console.error("Error: Failed to get changed files from git");
 52→    return [];
 53→  }
 54→}
 55→
 56→function readFileContent(filePath: string): string | null {
 57→  try {
 58→    return fs.readFileSync(filePath, "utf-8");
 59→  } catch {
 60→    return null;
 61→  }
 62→}
 63→
 64→function main(): void {
 65→  const args = parseArgs();
 66→  const testFiles = getChangedTestFiles();
 67→
 68→  if (testFiles.length === 0) {
 69→    if (args.json) {
 70→      console.log(
 71→        JSON.stringify({
 72→          status: "skip",
 73→          message: "No test files in diff",
 74→          summary: { totalFiles: 0, totalTests: 0, totalTautological: 0 },
 75→        }),
 76→      );
 77→    } else {
 78→      console.log("No test files changed in diff");
 79→    }
 80→    process.exit(0);
 81→  }
 82→
 83→  // Read file contents
 84→  const files: Array<{ path: string; content: string }> = [];
 85→  for (const filePath of testFiles) {
 86→    const content = readFileContent(filePath);
 87→    if (content !== null) {
 88→      files.push({ path: filePath, content });
 89→    } else if (args.verbose) {
 90→      console.error(`Warning: Could not read ${filePath}`);
 91→    }
 92→  }
 93→
 94→  // Run detection
 95→  const results = detectTautologicalTests(files);
 96→  const verdictImpact = getTautologyVerdictImpact(results);
 97→
 98→  if (args.json) {
 99→    console.log(
100→      JSON.stringify({
101→        status: verdictImpact,
102→        summary: results.summary,
103→        files: results.fileResults.map((f) => ({
104→          path: f.filePath,
105→          totalTests: f.totalTests,
106→          tautologicalCount: f.tautologicalCount,
107→          tautologicalTests: f.testBlocks
108→            .filter((b) => b.isTautological)
109→            .map((b) => ({
110→              line: b.lineNumber,
111→              description: b.description,
112→              style: b.style,
113→            })),
114→        })),
115→      }),
116→    );
117→  } else {
118→    console.log(formatTautologyResults(results));
119→  }
120→
121→  // Exit with appropriate code
122→  if (verdictImpact === "blocking") {
123→    process.exit(1);
124→  }
125→  process.exit(0);
126→}
