  2→/**
  3→ * CLI script for running upstream assessments
  4→ * Usage:
  5→ *   npx tsx scripts/upstream/assess.ts                    # Assess latest
  6→ *   npx tsx scripts/upstream/assess.ts v2.1.29           # Assess specific version
  7→ *   npx tsx scripts/upstream/assess.ts --since v2.1.25   # Assess since version
  8→ *   npx tsx scripts/upstream/assess.ts --dry-run         # Dry run mode
  9→ *   npx tsx scripts/upstream/assess.ts --help            # Show help
 10→ */
 11→
 12→import {
 13→  runUpstream,
 14→  validateVersion,
 15→  checkGhCliAvailable,
 16→} from "../../src/lib/upstream/index.js";
 17→import type { AssessmentOptions } from "../../src/lib/upstream/types.js";
 18→
 19→function showHelp(): void {
 20→  console.log(`
 21→Upstream Assessment CLI
 22→
 23→Usage:
 24→  npx tsx scripts/upstream/assess.ts [options] [version]
 25→
 26→Options:
 27→  --since <version>   Assess all versions since the specified version
 28→  --dry-run          Generate report but don't create issues
 29→  --force            Re-assess even if already assessed
 30→  --help             Show this help message
 31→
 32→Examples:
 33→  npx tsx scripts/upstream/assess.ts                    # Assess latest release
 34→  npx tsx scripts/upstream/assess.ts v2.1.29           # Assess specific version
 35→  npx tsx scripts/upstream/assess.ts --since v2.1.25   # Assess all since v2.1.25
 36→  npx tsx scripts/upstream/assess.ts --dry-run         # Preview without creating issues
 37→`);
 38→}
 39→
 40→async function main(): Promise<void> {
 41→  const args = process.argv.slice(2);
 42→
 43→  // Parse arguments
 44→  const options: AssessmentOptions = {};
 45→  let positionalVersion: string | undefined;
 46→
 47→  for (let i = 0; i < args.length; i++) {
 48→    const arg = args[i];
 49→
 50→    if (arg === "--help" || arg === "-h") {
 51→      showHelp();
 52→      process.exit(0);
 53→    }
 54→
 55→    if (arg === "--dry-run") {
 56→      options.dryRun = true;
 57→      continue;
 58→    }
 59→
 60→    if (arg === "--force") {
 61→      options.force = true;
 62→      continue;
 63→    }
 64→
 65→    if (arg === "--since") {
 66→      const nextArg = args[i + 1];
 67→      if (!nextArg || nextArg.startsWith("-")) {
 68→        console.error("Error: --since requires a version argument");
 69→        process.exit(1);
 70→      }
 71→      options.since = nextArg;
 72→      i++; // Skip next arg
 73→      continue;
 74→    }
 75→
 76→    // Positional argument (version)
 77→    if (!arg.startsWith("-")) {
 78→      positionalVersion = arg;
 79→    }
 80→  }
 81→
 82→  // Set version from positional arg if provided
 83→  if (positionalVersion) {
 84→    options.version = positionalVersion;
 85→  }
 86→
 87→  // Validate version inputs early to provide clear error messages
 88→  try {
 89→    if (options.version) {
 90→      validateVersion(options.version);
 91→    }
 92→    if (options.since) {
 93→      validateVersion(options.since);
 94→    }
 95→  } catch (error) {
 96→    console.error(
 97→      `Error: ${error instanceof Error ? error.message : "Invalid version format"}`,
 98→    );
 99→    console.error(
100→      "Version must be in semver format (e.g., v1.2.3 or 1.2.3-beta.1)",
101→    );
102→    process.exit(1);
103→  }
104→
105→  // Check gh CLI availability
106→  const ghStatus = await checkGhCliAvailable();
107→  if (!ghStatus.available || !ghStatus.authenticated) {
108→    console.error(`Error: ${ghStatus.error}`);
109→    process.exit(1);
110→  }
111→
112→  // Run assessment
113→  console.log("Starting upstream assessment...");
114→  console.log(`Options: ${JSON.stringify(options)}`);
115→
116→  try {
117→    const result = await runUpstream(options);
118→
119→    if (!result) {
120→      console.log(
121→        "No assessment performed (already assessed or no releases found)",
122→      );
123→      process.exit(0);
124→    }
125→
126→    // Print summary
127→    if ("assessments" in result) {
128→      // BatchedAssessment
129→      console.log("\n=== Batched Assessment Complete ===");
130→      console.log(`Versions assessed: ${result.versions.length}`);
131→      console.log(`From: ${result.sinceVersion} → ${result.toVersion}`);
132→      if (result.summaryIssueNumber) {
133→        console.log(`Summary issue: #${result.summaryIssueNumber}`);
134→      }
135→    } else {
136→      // Single UpstreamAssessment
137→      console.log("\n=== Assessment Complete ===");
138→      console.log(`Version: ${result.version}`);
139→      console.log(`Breaking changes: ${result.summary.breakingChanges}`);
140→      console.log(`Deprecations: ${result.summary.deprecations}`);
141→      console.log(`New tools: ${result.summary.newTools}`);
142→      console.log(`Hook changes: ${result.summary.hookChanges}`);
143→      console.log(`Opportunities: ${result.summary.opportunities}`);
144→      console.log(`No action: ${result.summary.noAction}`);
145→      if (result.issuesCreated.length > 0) {
146→        console.log(
147→          `Issues created: ${result.issuesCreated.map((n) => `#${n}`).join(", ")}`,
148→        );
149→      }
150→    }
151→
152→    console.log("\nDone!");
153→  } catch (error) {
154→    console.error("Assessment failed:", error);
155→    process.exit(1);
156→  }
157→}
